import{c as i,Q as a,j as e,m as l}from"./chunks/framework.CBiVa4O3.js";const o=JSON.parse('{"title":"零拷贝","description":"","frontmatter":{},"headers":[],"relativePath":"../osLearning/23-零拷贝.md","filePath":"../osLearning/23-零拷贝.md","lastUpdated":1778496697000}'),p={name:"../osLearning/23-零拷贝.md"};function n(t,s,h,k,d,r){return a(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="零拷贝" tabindex="-1">零拷贝 <a class="header-anchor" href="#零拷贝" aria-label="Permalink to &quot;零拷贝&quot;">​</a></h1><p>零拷贝不是&quot;一次拷贝都没有&quot;,而是减少 CPU 参与的数据搬运。普通 <code>read + write</code> 发送文件要把数据从磁盘搬到内核,再拷到用户态,再拷回内核 socket buffer,最后 DMA 到网卡。零拷贝用 <code>sendfile</code>、<code>splice</code>、<code>mmap</code>、DMA、页引用传递等手段,减少用户态/内核态拷贝和上下文切换。这一篇讲清楚:<strong>哪些拷贝能省、sendfile 为什么快、mmap 适合什么、零拷贝的边界在哪里</strong>。</p><blockquote><p>一句话先记住:<strong>零拷贝的核心是少让 CPU 搬大块数据</strong>。它通常省的是&quot;内核 ↔ 用户态&quot;拷贝,磁盘到内存、内存到网卡仍靠 DMA。<strong>静态文件发送、代理转发、日志传输适合零拷贝;需要加密、压缩、改内容时往往绕不开用户态处理</strong>。</p></blockquote><hr><h2 id="一、普通-read-write-有几次拷贝" tabindex="-1">一、普通 read + write 有几次拷贝 <a class="header-anchor" href="#一、普通-read-write-有几次拷贝" aria-label="Permalink to &quot;一、普通 read + write 有几次拷贝&quot;">​</a></h2><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">read</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(file_fd, buf, len);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">write</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sock_fd, buf, len);</span></span></code></pre></div><p>发送文件路径:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>磁盘 → DMA → page cache          1 次 DMA</span></span>
<span class="line"><span>page cache → 用户 buffer         1 次 CPU copy</span></span>
<span class="line"><span>用户 buffer → socket buffer      1 次 CPU copy</span></span>
<span class="line"><span>socket buffer → 网卡             1 次 DMA</span></span></code></pre></div><p>还有两次 syscall:<code>read</code> 和 <code>write</code>。</p><p>大文件传输时,CPU copy 很贵,而且污染 cache。</p><hr><h2 id="二、sendfile" tabindex="-1">二、sendfile <a class="header-anchor" href="#二、sendfile" aria-label="Permalink to &quot;二、sendfile&quot;">​</a></h2><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ssize_t</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sendfile</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> out_fd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> in_fd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">off_t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">offset</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">size_t</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> count</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>典型:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sendfile</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sock_fd, file_fd, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">off</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, len);</span></span></code></pre></div><p>路径:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>磁盘 → DMA → page cache</span></span>
<span class="line"><span>page cache → socket/网卡描述符引用</span></span>
<span class="line"><span>网卡 DMA 读 page cache 数据发送</span></span></code></pre></div><p>减少:</p><ul><li>用户态 buffer</li><li>内核到用户态拷贝</li><li>用户态到内核拷贝</li><li>一次 syscall</li></ul><p>Nginx 静态文件发送大量使用 sendfile。</p><h3 id="_2-1-限制" tabindex="-1">2.1 限制 <a class="header-anchor" href="#_2-1-限制" aria-label="Permalink to &quot;2.1 限制&quot;">​</a></h3><p>sendfile 适合&quot;文件原样发到 socket&quot;。</p><p>不适合:</p><ul><li>需要压缩内容</li><li>需要应用层加密处理</li><li>需要改包体</li><li>源/目标不是支持的 fd 类型</li></ul><p>TLS 是典型限制:用户态 TLS 要读出明文加密后再发。内核 TLS(kTLS)可以缓解部分场景。</p><hr><h2 id="三、mmap" tabindex="-1">三、mmap <a class="header-anchor" href="#三、mmap" aria-label="Permalink to &quot;三、mmap&quot;">​</a></h2><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> mmap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">NULL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, len, PROT_READ, MAP_PRIVATE, fd, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">write</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sock_fd, p, len);</span></span></code></pre></div><p><code>mmap</code> 把文件映射进进程虚拟地址:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>访问 p[i]</span></span>
<span class="line"><span>  → 缺页中断</span></span>
<span class="line"><span>  → 文件页读入 page cache</span></span>
<span class="line"><span>  → 页表映射到进程</span></span></code></pre></div><p>省掉 <code>read</code> 的用户态 buffer 拷贝,但 <code>write</code> 到 socket 仍可能拷贝到 socket buffer。</p><p>适合:</p><ul><li>随机读文件</li><li>多进程共享只读数据</li><li>大文件局部访问</li><li>数据库/搜索引擎某些索引结构</li></ul><p>不适合:</p><ul><li>顺序流式读写简单场景未必比 read 快</li><li>访问越界 SIGBUS</li><li>page fault 延迟不可控</li><li>写 mmap 文件的一致性要小心</li></ul><hr><h2 id="四、splice-tee-vmsplice" tabindex="-1">四、splice / tee / vmsplice <a class="header-anchor" href="#四、splice-tee-vmsplice" aria-label="Permalink to &quot;四、splice / tee / vmsplice&quot;">​</a></h2><p>Linux pipe 可以作为内核中的数据管道。</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">splice</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(file_fd, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">NULL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">pipefd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">NULL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, len, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">splice</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">pipefd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">NULL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, sock_fd, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">NULL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, len, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>数据在内核对象之间移动,尽量不经过用户态。</p><p>用途:</p><ul><li>文件到 socket</li><li>socket 到文件</li><li>pipe 间复制</li><li>代理转发</li></ul><p><code>tee</code> 可以在 pipe 之间复制引用,<code>vmsplice</code> 可以把用户页映射到 pipe。</p><p>工程上比 sendfile 更灵活,也更难用。</p><hr><h2 id="五、dma-与-scatter-gather" tabindex="-1">五、DMA 与 scatter-gather <a class="header-anchor" href="#五、dma-与-scatter-gather" aria-label="Permalink to &quot;五、DMA 与 scatter-gather&quot;">​</a></h2><p>DMA(Direct Memory Access)让设备直接读写内存,CPU 不逐字节搬。</p><p>Scatter-gather IO 让设备一次处理多个内存片段:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">writev</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, iov, iovcnt);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sendmsg</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">msg</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>优点:</p><ul><li>避免把多个 buffer 拼成一个大 buffer</li><li>减少内存拷贝</li><li>网络协议栈常用</li></ul><hr><h2 id="六、零拷贝和页缓存" tabindex="-1">六、零拷贝和页缓存 <a class="header-anchor" href="#六、零拷贝和页缓存" aria-label="Permalink to &quot;六、零拷贝和页缓存&quot;">​</a></h2><p>sendfile 通常仍走 page cache:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>磁盘数据进 page cache</span></span>
<span class="line"><span>网卡从这些页发出去</span></span></code></pre></div><p>这对热点静态文件很好:第二次发送直接内存命中。</p><p>但对超大冷文件可能污染 page cache。可以考虑:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">posix_fadvise</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, POSIX_FADV_SEQUENTIAL);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">posix_fadvise</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, POSIX_FADV_DONTNEED);</span></span></code></pre></div><p>或用 <code>O_DIRECT</code> 让应用自己管理缓存。</p><hr><h2 id="七、什么时候零拷贝收益大" tabindex="-1">七、什么时候零拷贝收益大 <a class="header-anchor" href="#七、什么时候零拷贝收益大" aria-label="Permalink to &quot;七、什么时候零拷贝收益大&quot;">​</a></h2><p>收益大:</p><ul><li>大文件静态下载</li><li>视频点播</li><li>反向代理转发</li><li>日志/备份传输</li><li>CPU 被 copy 打满</li></ul><p>收益小:</p><ul><li>小响应,业务计算占主导</li><li>数据需要修改</li><li>TLS/压缩在用户态</li><li>瓶颈在磁盘或网络带宽</li></ul><hr><h2 id="八、常见坑" tabindex="-1">八、常见坑 <a class="header-anchor" href="#八、常见坑" aria-label="Permalink to &quot;八、常见坑&quot;">​</a></h2><ol><li><strong>以为零拷贝就是 0 copy</strong>:DMA 和必要的内核内部引用仍存在。</li><li><strong>忽略短发送</strong>:<code>sendfile</code> 也可能只发一部分。</li><li><strong>TLS 破坏零拷贝路径</strong>:加密要处理明文。</li><li><strong>mmap 后访问触发 SIGBUS</strong>:文件被截断或映射越界。</li><li><strong>page cache 污染</strong>:大冷文件挤掉热数据。</li><li><strong>跨文件系统/特殊 fd 不支持</strong>:要处理 fallback。</li></ol><hr><h2 id="九、排查与验证" tabindex="-1">九、排查与验证 <a class="header-anchor" href="#九、排查与验证" aria-label="Permalink to &quot;九、排查与验证&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">strace</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> read,write,sendfile,splice</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">perf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> top</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pidstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> DEV</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span></code></pre></div><p>如果 <code>perf top</code> 里大量 <code>copy_user_enhanced_fast_string</code> / <code>memcpy</code>,说明 CPU 在搬数据,零拷贝可能有价值。</p><blockquote><p><strong>结论</strong>:零拷贝是大吞吐场景的利器,但它优化的是数据搬运路径。先确认 CPU copy 是瓶颈,再选择 sendfile/splice/mmap/writev,不要为了术语复杂化普通业务代码。</p></blockquote>`,73)])])}const g=i(p,[["render",n]]);export{o as __pageData,g as default};
